def ones_complement(bits):
    return "".join("1" if b == "0" else "0" for b in bits)

def twos_complement(bits):
    ones = ones_complement(bits)
    carry = 1
    result = list(ones)
    for i in range(len(result) - 1, -1, -1):
        total = int(result[i]) + carry
        result[i] = str(total % 2)
        carry = total // 2
        if carry == 0:
            break
    return "".join(result)

n = "10110"
print(f"2진수: {n}")
print(f"1의 보수: {ones_complement(n)}")
print(f"2의 보수: {twos_complement(n)}")
